export type ParsedPrimaryPurchaseInstruction<
  TProgram extends string = typeof CENTLALIA_TICKETING_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    buyer: TAccountMetas[0];
    platformConfig: TAccountMetas[1];
    event: TAccountMetas[2];
    tier: TAccountMetas[3];
    organizer: TAccountMetas[4];
    treasury: TAccountMetas[5];
    ticketRecord: TAccountMetas[6];
    managedAsset: TAccountMetas[7];
    assetAuthority: TAccountMetas[8];
    systemProgram: TAccountMetas[9];
  };
  data: PrimaryPurchaseInstructionData;
};

export function parsePrimaryPurchaseInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedPrimaryPurchaseInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 10) {
    throw new SolanaError(SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS, {
      actualAccountMetas: instruction.accounts.length,
      expectedAccountMetas: 10,
    });
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      buyer: getNextAccount(),
      platformConfig: getNextAccount(),
      event: getNextAccount(),
      tier: getNextAccount(),
      organizer: getNextAccount(),
      treasury: getNextAccount(),
      ticketRecord: getNextAccount(),
      managedAsset: getNextAccount(),
      assetAuthority: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getPrimaryPurchaseInstructionDataDecoder().decode(instruction.data),
  };
}
